import React, {Component} from 'react';
import algoliasearch from 'algoliasearch';
import { InstantSearch, SearchBox, connectHits, connectPagination, Configure, Stats, connectStateResults, connectGeoSearch } from 'react-instantsearch-dom';

import './App.css';
import L from "leaflet";

const searchClient = algoliasearch('0HAV8OIN0H', 'e43a69fc7d9c3607d9a4e677c8b250dd');
// const index = searchClient.initIndex("Housing");
let size=0;
let lat=[size], lng=[size], distance=[];

function getDistance(lat1,lon1,lat2,lon2) {
    var R = 6371; // km (change this constant to get miles)
    var dLat = (lat2-lat1) * Math.PI / 180;
    var dLon = (lon2-lon1) * Math.PI / 180;
    var a = Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(lat1 * Math.PI / 180 ) * Math.cos(lat2 * Math.PI / 180 ) *
        Math.sin(dLon/2) * Math.sin(dLon/2);
    var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    var d = R * c;
    // if (d>1) return Math.round(d);
    return Math.round(d*0.621371);
}

const Pagination = ({ currentRefinement, nbPages, refine }) => {
    let page = currentRefinement;
    return(
        <div className="pagination">
            <div className="results">
                <Stats
                    translations={{
                        stats(nbHits) {
                            size = nbHits;
                            return `${nbHits} results`;
                        },
                    }}
                />
            </div>
            <div className="navigation">
                <p>Page {currentRefinement}</p>
                <div className="arrows">
                    <a
                        className="prev-page arrow"
                        href="#"
                        onClick={event => {
                            event.preventDefault();
                            if(page>1) page=currentRefinement-1
                            refine(page);
                        }}
                    ><span>&#60;</span></a>
                    <a
                        className="next-page arrow"
                        href="#"
                        onClick={event => {
                            event.preventDefault();
                            if(page<nbPages) page=currentRefinement+1;
                            refine(page);
                        }}
                    ><span>&#62;</span></a>
                </div>
            </div>
        </div>
    );
}

const CustomPagination = connectPagination(Pagination);

const hits = ({ hits, myLat, myLng }) => {
    hits.forEach((hit, index)=>{
        lat[index]=hit._geoloc.lat;
        lng[index]=hit._geoloc.lng;
    });
    for(let i=0; i<size; i++){
        distance[i] = getDistance(lat[i], lng[i], myLat, myLng);
    }
    console.log(hits[0]);
    return(
        <div className="hits">
            <CustomPagination />
            {hits.map((hit, index) => (
                <div key={hit.objectID}>
                    <div className="hit">
                        <div className="left">
                            <div className="top-row">
                                <h2 className="name">{hit.property_name}</h2>
                                <p className="status">Pet policy status</p>
                            </div>
                            <div className="underline">
                                <div className="contacts">
                                    <p className="phone"><a href={"tel:"+hit.phone.replace(/\D+/g, "")}>{hit.phone}</a></p>
                                    <p className="email">{ hit.email ? <a href={"mail-to:"+hit.email}>{hit.email}</a> : "Don`t have an email"}</p>
                                </div>
                                <p className="status-info">{hit.pet_policy}</p>
                            </div>
                            <p className="address">Address:
                                <br/>
                                <span>{hit.address.street} ({hit.address.state}), {hit.address.city}, {hit.address.zip}</span>
                            </p>
                        </div>
                        <div className="right">
                            <p className="distance">{distance[index]} Miles</p>
                            <a className="website" href={hit.website} target="_blank" rel="noopener noreferrer">View website</a>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
}

const CustomHits = connectHits(hits);

const HitsResult = connectStateResults(
    ({ searchState }, myLat, myLng) =>
        searchState && searchState.query ? (
                <CustomHits myLat={myLat} myLng={myLng}/>
            ) : //<div>No query</div>
            null
);

class GeoSearch extends Component {
    markers = [];
    zoom = 11;

    componentDidMount() {
        this.instance = L.map(this.el);

        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution:
               ''
        }).addTo(this.instance);
    }

    async componentDidUpdate() {
        console.log('Did Update');
        const { hits, latitude, longitude,  initialZoom } = this.props;
        console.log(initialZoom);

        this.markers.forEach(marker => marker.remove());

        // await connectStateResults(
        //     ({ searchState }) =>
        //         searchState && searchState.query ? (
                        this.markers = hits.map(({ _geoloc }) =>
                            L.marker([_geoloc.lat, _geoloc.lng]).addTo(this.instance)
                        )
        //             ) : null
        // );
        console.log(this.markers);
        if (this.markers.length) {
            if (this.zoom === initialZoom) {

                this.zoom = initialZoom;
                this.instance.fitBounds(L.featureGroup(this.markers).getBounds(), {
                    animate: true
                });
            } else {
                this.zoom = initialZoom
                this.instance.setZoom(initialZoom, {
                    animate: true
                })
            }
        } else {
            this.zoom = initialZoom;
            console.log('initialZoom', initialZoom);
            this.instance.setView(
                {
                    lat: latitude,
                    lng: longitude,
                },
                initialZoom,
                {
                    animate: true,
                }
            );
        }
    }

    render() {
        return <div style={{ height: 500, width: '50%' }} ref={c => (this.el = c)} />;
    }
}

const CustomGeoSearch = connectGeoSearch(GeoSearch);

class FrontPage extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            latitude: 0,
            longitude: 0,
            initialZoom: 11,
            value: 10
        };
        this.getMyLocation = this.getMyLocation.bind(this);
        this.radiusToZoom = this.radiusToZoom.bind(this);
        this.setRange = this.setRange.bind(this);
        // this.deg2rad = this.deg2rad.bind(this);
    }

    componentDidMount() {
        this.getMyLocation()
    }

    getMyLocation() {
        const location = window.navigator && window.navigator.geolocation

        if (location) {
            location.getCurrentPosition((position) => {
                this.setState({
                    latitude: parseFloat(position.coords.latitude),
                    longitude: parseFloat(position.coords.longitude),
                })
            }, (error) => {
                this.setState({ latitude: 'err-latitude', longitude: 'err-longitude' })
            })
        }

    }

    radiusToZoom(radius){
        return Math.round(14-Math.log(radius)/Math.LN2);
    }

    setRange(event){
        this.setState({
            value: event.target.value,
            initialZoom: this.radiusToZoom(event.target.value)
        });
        // console.log(this.radiusToZoom(event.target.value))
    }

    render(){
        return(<div className="container">
                <InstantSearch searchClient={searchClient} indexName="Housing" >
                    <Configure filters="_show:true" />
                    <div className="row">
                        <CustomGeoSearch hits={hits} initialZoom={this.state.initialZoom} latitude={this.state.latitude} longitude={this.state.longitude}  />
                        <div className="col">
                            <div className="search">
                                <SearchBox reset="reset"/>
                                <label>
                                    <select value={this.state.value} onChange={this.setRange}>
                                        <option value="10">10</option>
                                        <option value="20">20</option>
                                        <option value="50">50</option>
                                        <option value="100">100</option>
                                    </select>
                                </label>
                            </div>
                            <HitsResult myLat={this.state.latitude} myLng={this.state.longitude}/>
                        </div>
                    </div>
                </InstantSearch>
            </div>
        );
    }
}

export default FrontPage;
